/**
 * Model RetailProduct
 * A brand's ready-to-buy retail product listing.
 * Distinct from Campaign (pre-order / Back It) — these are in-stock products
 * available for immediate purchase via the Loocbooc retail storefront.
 */
export type RetailProduct = $Result.DefaultSelection<Prisma.$RetailProductPayload>
/**
 * Model ProductVariant
 * A purchasable variant of a RetailProduct — each combination of colour + size is one variant.
 * This is what goes in the cart. The variant tracks its own stock level.
 */
export type ProductVariant = $Result.DefaultSelection<Prisma.$ProductVariantPayload>
/**
 * Model Cart
 * Persistent shopping cart — one cart per user, cleared on checkout.
 * Guest carts are keyed by a sessionToken (stored in cookie) with no userId.
 */
export type Cart = $Result.DefaultSelection<Prisma.$CartPayload>
/**
 * Model CartItem
 * An individual line item in a shopping cart.
 */
export type CartItem = $Result.DefaultSelection<Prisma.$CartItemPayload>
/**
 * Model RetailOrder
 * Retail order — created when a consumer checks out from the retail platform.
 * Distinct from Order (which covers all order types including Back It).
 */
export type RetailOrder = $Result.DefaultSelection<Prisma.$RetailOrderPayload>
/**
 * Model RetailOrderItem
 * Line items in a retail order.
 */
export type RetailOrderItem = $Result.DefaultSelection<Prisma.$RetailOrderItemPayload>
/**
 * Model LookbookItemProduct
 * Junction table — allows lookbook items to reference retail products (in addition to campaigns/SKUs).
 */
export type LookbookItemProduct = $Result.DefaultSelection<Prisma.$LookbookItemProductPayload>
/**
 * Model Notification
 * In-app notifications for consumers.
 * Notifications are created by background workers (BullMQ) and the API
 * when significant events occur. They provide a persistent record of
 * important updates that persists beyond email delivery.
 */
export type Notification = $Result.DefaultSelection<Prisma.$NotificationPayload>

